# DK LST.  Langå - Struer
#
let ls = path("d3.dk.lst");

with detail = 3, railway = :first :pax {
    # point.dk.Langå  dk.FFH

    with link = "line.dk.LST" {
        track(:lor,
                ls[:lan.ys - 0.1dl, :lan.ys] >> 0.5md >> 1ms >> 0.5mt
            ..  ls[:lan.xs + 2mt, :lan.xs + 2.1mt]
        );
        track(ls[:lan.xs + 2mt, :abr - 0.49sw]);
    }

    with link = "point.dk.Åbro", railway = :station {
        track(ls[:abr - 0.5sw, :abr + 0.5sw]);
        marker(:left :de.hp :removed, ls[:abr] << 0.5mt);
        slabel(:bottom :removed, ls[:abr] << 0.5mt << 1sh + (-1dt, 0.4dt),
            "Åbro"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:abr + 0.49sw, :abr + 2.11km]);
        line_label(:right:s, ls[:abr + 2.1km] >> 0.5mt, "LST");
        track(ls[:abr + 2.09km, :uls - 0.49sw]);
    }

    with link = "point.dk.Ulstrup", railway = :station {
        track(ls[:uls - 0.5sw, :uls + 0.5sw]);
        marker(:right :de.bf, ls[:uls] >> 0.5mt);
        slabel(:top, ls[:uls] >> 0.5mt >> 1sh >> 0.3dt, "Ulstrup");
    }

    with link = "line.dk.LST" {
        track(ls[:uls + 0.49sw, :bje - 0.49sw]);
    }

    with link = "point.dk.Bjerringbro", railway = :station {
        track(ls[:bje - 0.5sw, :bje + 0.5sw]);
        marker(:right :de.bf, ls[:bje] >> 0.5mt);
        slabel(:left, ls[:bje] >> 0.5mt >> 1sh + (-1.7dt, 0.1dt),
            "Bjerringbro"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:bje + 0.49sw, :tan - 0.49sw]);
    }

    with link = "point.dk.Tange", railway = :station {
        track(ls[:tan - 0.5sw, :tan + 0.5sw]);
        marker(:right :de.hst :removed, ls[:tan] >> 0.5mt);
        slabel(:left :removed, ls[:tan] >> 0.5mt >> 1sh + (-1.7dt, 0.1dt),
            "Tange"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:tan + 0.49sw, :tan + 2.51km]);
        line_label(:left:n, ls[:tan + 2.5km] << 0.5mt, "LST");
        track(ls[:tan + 2.49km, :rod - 0.5sw - 1.9dl]);
    }

    with link = "point.dk.Rødkærsbro", railway = :station {
        track(:removed,
                ls[:rod - 0.5sw - 1.1dl, :rod - 0.5sw - 1dl]
            --  ls[:rod - 0.5sw, :rod.ys] << 1ms << 1mt
        );
        track(ls[:rod - 0.5sw - 2dl, :rod.ys]);
        marker(:right :de.bf, ls[:rod] >> 0.5mt);
        slabel(:top, ls[:rod] >> 0.5mt >> 1sh + (2dt, -0.8dt),
            span(:bold, "Rødkærsbro")
        );
    }

    with link = "line.dk.LST" {
        track(ls[:rod.ys - 0.1dl, :rod + 4.01km]);
        line_label(:right:w, ls[:rod + 4km] >> 0.5mt, (0dt, -0.3dt), "LST");
        track(ls[:rod + 3.99km, :rin - 0.49sw]);
    }

    with link = "point.dk.Rindsholm", railway = :station {
        track(ls[:rin - 0.5sw, :rin + 0.5sw]);
        marker(:right :de.bbf :nopax, ls[:rin] >> 0.5mt);
        marker(:right :de.exbf :nopax, ls[:rin] >> 0.5mt);
        slabel(:right :nopax, ls[:rin] >> 0.5mt >> 1.4sh + (1.5dt, 0.6dt),
            "Rindsholm"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:rin + 0.49sw, :rin + 1.51km]);
        line_label(:right:sw, ls[:rin + 1.5km] >> 0.5mt, "LST");
        track(ls[:rin + 1.49km, :vib.yv]);
        track(ls[:vib.yv - 0.1dl, :vib.yh - 0.9seg]);
        track(:lor, ls[:vib.yh - 1.1seg, :vib.yh + 0.1dl]);
        track(:lor, ls[:vib.yh, :vib - 399m]);
    }

    with link = "point.dk.Viborg", railway = :station {
        track(:removed,
                ls[:vib - 400m, :vib + 500m - 2dl] << 2ms << 2mt
            --  ls[:vib + 500m, :vib + 501m]
        );

        # DK HVI
        track(:removed,
                ls[:vib - 400m, :vib + 500m - 1dl] << 1ms << 1mt
        );

        # DK LST
        track(ls[:vib - 400m, :vib + 550m]);

        track(:removed,
                ls[:vib - 351m, :vib - 350m]
            --  ls[:vib - 350m + 1dl, :vib + 550m] >> 1ms >> 1mt
        );
        marker(:right :de.bf, ls[:vib] >> 1ms >> 1.5mt);
        slabel(:right :bold, ls[:vib] >> 1ms >> 1.5mt >> 1sh + (1.5dt, 0.3dt),
            "Viborg"
        );
    }

    with link = "line.dk.LST" {
        track(:ror, ls[:vib + 549m, :vib.ya]);
        track(:ror, ls[:vib.ya - 0.1dl, :vib.ys]);
        track(:ror:lor, ls[:vib.ys - 0.1dl, :vib.ys + 1seg]);
        track(ls[:vib.ys + 0.9seg, :vib.ys + 2.01km]);
        line_label(:right:s, ls[:vib.ys + 2km] >> 0.5mt, "LST");
        track(ls[:vib.ys + 1.99km, :rav - 0.49sw]);
    }

    with link = "point.dk.Ravnstrup", railway = :station {
        track(ls[:rav - 0.5sw, :rav + 0.5sw]);
        marker(:left :de.bbf :nopax :casing, ls[:rav] << 0.5mt);
        marker(:left :de.exbf :nopax :casing, ls[:rav] << 0.5mt);
        slabel(:right :nopax, ls[:rav] >> 0.5mt + (1dt, 0dt), "Ravnstrup");
    }

    with link = "line.dk.LST" {
        track(:lor, ls[:rav + 0.49sw, :rav.yv + 0.1dl]);
    }
}

with detail = 3, railway = :first :pax :removed {
    let lv = path("d3.dk.lst.vio");
    let vs = path("d3.dk.lst.vis");
    let vv = path("d3.dk.lst.viv");

    with link = "line.dk.LST" {
        track(:ror, lv[:vib.yv, :vib.ys + 0.1dl]);
        track(lv[:vib.ys, :vib - 0.49sw]);
    }

    with link = "point.dk.Viborg", railway = :station {
        track(lv[:vib - 0.5sw, :vib + 0.5sw]);
        marker(:left :de.bf :casing, lv[:vib] << 0.5mt);
    }

    with link = "line.dk.LST" {
        track(:lor, vs[:vib.ys, :vib.ys + 1seg]);
        track(vs[:vib.ys + 0.9seg, :vib.yv - 0.9seg]);
        track(:ror, vs[:vib.yv - 1seg, :vib.yv]);

        track(vs[:vib.yv, :vib.yv + 0.81km]);
        line_label(:left:n, vs[:vib.yv + 0.8km] << 0.5mt,
            (-0.5dt, 0dt), "LST"
        );
        track(vs[:vib.yv + 0.79km, :rav - 0.49sw]);
    }

    with link = "point.dk.Ravnstrup", railway = :station {
        track(vs[:rav - 0.5sw, :rav + 0.5sw]);
        marker(:left :de.bf, vs[:rav] << 0.5mt);
        slabel(:left, vs[:rav] << 0.5mt << 1sh + (-1.7dt, 1.5dt),
            "Ravnstrup"
        );
    }

    with link = "line.dk.LST" {
        track(vs[:rav + 0.49sw, :rav.yv - 0.9seg]);
        track(:ror, vs[:rav.yv - 1seg, :rav.yv]);
    }

    with link = "line.dk.LST" {
        track(:ror, vv[:vib.ys, :vib.ys + 1seg]);
        track(vv[:vib.ys + 0.9seg, :vib.yv - 0.9seg]);
        track(:lor, vv[:vib.yv - 1seg, :vib.yv]);
    }
}

with detail = 3, railway = :first :pax {
    with link = "line.dk.LST" {
        track(ls[:rav.yv, :spa - 0.49sw]);
    }

    with link = "point.dk.Sparkær", railway = :station {
        track(ls[:spa - 0.5sw, :spa + 0.5sw]);
        marker(:right :de.hp, ls[:spa] >> 0.5mt);
        marker(:right :de.exbf, ls[:spa] >> 0.5mt);
        slabel(:top, ls[:spa] >> 0.5mt >> 1.4sh + (-0.5dt, -0.3dt),
            "Sparkær"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:spa + 0.49sw, :sto - 0.49sw]);
    }

    with link = "point.dk.Stoholm", railway = :station {
        track(ls[:sto - 0.5sw, :sto + 0.5sw]);
        marker(:left :de.bf, ls[:sto] << 0.5mt);
        slabel(:bottom, ls[:sto] << 0.5mt << 1sh + (-2dt, 0.8dt),
            "Stoholm"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:sto + 0.49sw, :sob - 0.49sw]);
    }

    with link = "point.dk.Søby", railway = :station {
        track(ls[:sob - 0.5sw, :sob + 0.5sw]);
        marker(:left :de.hp :removed, ls[:sob] << 0.5mt);
        slabel(:left :removed, ls[:sob] << 0.5mt << 1sh + (-1.2dt, 0.9dt),
            "Søby"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:sob + 0.49sw, :hoj - 0.49sw]);
    }

    with link = "point.dk.Højslev", railway = :station {
        track(ls[:hoj - 0.5sw, :hoj + 0.5sw]);
        marker(:right :de.bf, ls[:hoj] >> 0.5mt);
        slabel(:right, ls[:hoj] >> 0.5mt >> 1sh + (1.7dt, 0.7dt),
            "Højslev"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:hoj + 0.49sw, :hoj + 2.71km]);
        line_label(:left:ne, ls[:hoj + 2.7km] << 0.5mt, "LST");
        track(ls[:hoj + 2.69km, :ski.yo]);
        track(:station, ls[:ski.yo - 0.1dl, :ski - 0.5sw - 1.9dl]);
    }

    with link = "point.dk.Skive", railway = :station {
        track(ls[:ski - 0.5sw - 2dl, :ski + 0.5sw]);
        track(:removed,
                ls[:ski - 0.5sw - 1.1dl, :ski - 0.5sw - 1dl]
            --  ls[:ski - 0.5sw, :ski + 0.5sw] >> 1ms >> 1mt
        );
        marker(:right :de.bf, ls[:ski] >> 1ms >> 1.5mt);
        slabel(:top :bold, ls[:ski] >> 1ms >> 1.5mt >> 1sh + (1dt, -0.4dt),
            "Skive"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:ski + 0.49sw, :ski.yg]);
        track(:lor, ls[:ski.yg, :ski.yg + 1seg]);
        track(ls[:ski.yg + 0.9seg, :est + 0.1dl]);
    }
}

with detail = 3, railway = :first :pax :removed {
    let si = path("d3.dk.lst.ski");
    let ss = path("d3.dk.lst.sks");

    with link = "line.dk.LST" {
        track(:station, si[:ski.yo, :ski.ys]);
    }

    with link = "point.dk.Skive", railway = :station {
        track(si[:ski.ys, :ski + 0.5sw]);
        marker(:right :de.bf, si[:ski] >> 0.5mt);
    }

    with link = "line.dk.LST" {
        track(ss[:ski.ys - 0.1dl, :est]);
    }
}

with detail = 3, railway = :first :pax {
    with link = "point.dk.Estvad", railway = :station {
        marker(:left :de.anst :removed, ls[:est] << 0.5mt);
        slabel(:bottom :xsmall :removed, ls[:est] << 0.5mt << 1sh << 0.2dt,
            "Estvad"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:est - 0.1dl, :est + 2.21km]);
        line_label(:right:se, ls[:est + 2.2km] >> 0.5mt, "LST");
        track(ls[:est + 2.19km, :ron - 0.49sw]);
    }

    with link = "point.dk.Rønbjerg", railway = :station {
        track(ls[:ron - 0.5sw, :ron + 0.5sw]);
        marker(:left :de.bbf :nopax, ls[:ron] << 0.5mt);
        marker(:left :de.exbf :nopax, ls[:ron] << 0.5mt);
        slabel(:right :nopax, ls[:ron] << 0.5mt << 1.4sh + (1.5dt, 1.8dt),
            "Rønbjerg"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:ron + 0.49sw, :hvi - 0.49sw]);
    }

    with link = "point.dk.Hvide-Mose", railway = :station {
        track(ls[:hvi - 0.5sw, :hvi + 0.5sw]);
        marker(:left :de.hp :removed, ls[:hvi] << 0.5mt);
        slabel(:right :removed, ls[:hvi] << 0.5mt << 1.0sh + (1.5dt, 2dt),
            "Hvide-Mose"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:hvi + 0.49sw, :vin - 0.49sw]);
    }

    with link = "point.dk.Vinderup", railway = :station {
        track(ls[:vin - 0.5sw, :vin + 0.5sw]);
        marker(:right :de.bf, ls[:vin] >> 0.5mt);
        slabel(:left, ls[:vin] >> 0.5mt >> 1sh + (-1.7dt, 0.1dt),
            "Vinderup"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:vin + 0.49sw, :han - 0.49sw]);
    }

    with link = "point.dk.Handbjerg", railway = :station {
        track(ls[:han - 0.5sw, :han + 0.5sw]);
        marker(:right :de.hp :removed, ls[:han] >> 0.5mt);
        marker(:right :de.exbf :removed, ls[:han] >> 0.5mt);
        slabel(:left :removed, ls[:han] >> 0.5mt >> 1.4sh + (-1.7dt, 0.1dt),
            "Handbjerg"
        );
    }

    with link = "line.dk.LST" {
        track(ls[:han + 0.49sw, :han + 5.21km]);
        line_label(:right:s, ls[:han + 5.2km] >> 0.5mt, (0.5dt, 0dt), "LST");
        track(ls[:han + 5.19km, :str.xl]);
        track(:lor,
                ls[:str.xl - 0.1dl, :str.xl]
            ..  ls[:str.yl, :str.yl + 0.1dl] >> 1ms >> 1mt
        );
        track(:lor, ls[:str.yl, :str - 0.49sw] >> 1ms >> 1mt);
    }

    # point.dk.Struer  dk.LES
}

